for (const item of $input.all()) {
  const question = $('Luận giải tarot').first().json.body.question || "";
  const cards = $('Luận giải tarot').first().json.body.cards || [];
  const userProfile = $('Luận giải tarot').first().json.body.userProfile || { name: 'lữ khách', gender: 'bạn', user_persona: '' };
  const userName = userProfile.name;
  const userGender = userProfile.gender;
  const recentEvents = userProfile.user_persona;
  const readerPrompt = $('Luận giải tarot').first().json.body.reader_prompt || '';

  let isFollowUp = false;
  let historyText = "Chưa có.";

  // Lấy mảng history do Astro Webhook truyền sang
  const history = $('Luận giải tarot').first().json.body.history || [];

  if (history.length > 0) {
    isFollowUp = true;
    const historyLines = history.map(msg => {
      const speaker = msg.role === 'assistant' ? 'Tarot Reader' : 'Khách hàng';
      return `- ${speaker}: "${msg.content}"`;
    });
    historyText = `### [BỐI CẢNH CÁC LẦN TRẢI BÀI/TRÒ CHUYỆN TRƯỚC ĐÓ TRONG PHIÊN]\n${historyLines.join('\n')}`;
  }

  // Chèn Chân dung năng lượng
  let personaSection = '';
  if (recentEvents && recentEvents.trim() !== '') {
    personaSection = `\n\n### [CHÂN DUNG NĂNG LƯỢNG KHÁCH HÀNG (Do AI đúc kết từ các phiên trước)]\n${recentEvents}`;
  }

  // Prompt mặc định
  const defaultFirstPrompt = `## ROLE: Master Tarot Reader\n## TASK: Hóa thân thành một Tarot Reader sâu sắc, ấm áp, thấu cảm và chuyên nghiệp sử dụng bộ bài Rider–Waite. Giải đáp câu hỏi dựa trên các lá bài đã bốc.`;
  const defaultFollowUpPrompt = `## ROLE: Master Tarot Reader\n## TASK: Hóa thân thành một Tarot Reader sâu sắc, ấm áp. Lữ khách vừa bốc thêm 3 lá bài mới. Trực tiếp luận giải 3 lá bài MỚI này.`;

  const narrativeBase = readerPrompt || (isFollowUp ? defaultFollowUpPrompt : defaultFirstPrompt);

  let mySystemPrompt = "";
  if (!isFollowUp) {
    mySystemPrompt = narrativeBase + `\n\n## USER INFO: Tên: ${userName}, Xưng hô: ${userGender}. Hãy gọi tên và xưng hô tự nhiên như một người bạn tâm giao.` + personaSection + `\n\n## HƯỚNG DẪN LUẬN GIẢI:\n1. Kết nối ý nghĩa của 3 lá bài theo tiến trình thời gian (Quá khứ → Hiện tại → Tương lai) để tạo nên một câu chuyện mạch lạc.\n2. Lồng ghép cả "mặt sáng" và "bài học cần học", tuyệt đối không mê tín dị đoan.\n3. Giọng văn con người trầm ổn, đồng cảm.\n4. KHÔNG nhắc đến AI, thuật toán, máy tính, ngẫu nhiên hoặc "Xuôi". (Dùng từ: Hướng thuận, mặt thuận lợi...).\n5. Trình bày đẹp mắt bằng Markdown. Dưới 1000 tokens.\n\n## CẤU TRÚC BẮT BUỘC:\n---\nLời chào mở đầu (1–2 câu)\n### 1. Mở đầu và cảm nhận chung (2-3 câu)\n### 2. Dòng chảy của câu chuyện (Quá khứ → Hiện tại → Tương lai) (3-4 câu)\n### 3. Sự kết nối giữa các lá bài (3-4 câu)\n### 4. Lời khuyên từ trái tim (2-3 câu)\n→ Kết thúc bằng 1–2 câu hỏi tự vấn`;
  } else {
    mySystemPrompt = narrativeBase + `\n\n## USER INFO: Tên: ${userName}, Xưng hô: ${userGender}. Hãy gọi tên và xưng hô tự nhiên.` + personaSection + `\n\n## HƯỚNG DẪN LUẬN GIẢI:\n1. TRỰC TIẾP đi vào luận giải 3 lá bài mới, KHÔNG lặp lại lời chào sến súa. Nhắc đến tên lá bài để lữ khách biết bạn đang giải bài mới.\n2. Đảm bảo tính liên kết chặt chẽ với những gì bạn đã nói trong các lần trước (xem bối cảnh). KHÔNG tự mâu thuẫn với chính mình.\n3. Trình bày linh hoạt, tự nhiên như trò chuyện. KHÔNG theo outline rập khuôn.\n4. Ngắt đoạn linh hoạt, dùng bullet points tự do.\n5. Giọng văn trầm ổn. TUYỆT ĐỐI KHÔNG nhắc đến AI, thuật toán.`;
  }

  let cardsSection = "";
  if (cards.length > 0) {
    const cardPast = cards[0] || {};
    const cardPresent = cards[1] || {};
    const cardFuture = cards[2] || {};
    cardsSection = `### [LÁ BÀI & Ý NGHĨA]\n- Lá 1 (Quá khứ): ${cardPast.name || "?"} (${cardPast.orientation || "Xuôi"}) - ${cardPast.meaning || "?"}\n- Lá 2 (Hiện tại): ${cardPresent.name || "?"} (${cardPresent.orientation || "Xuôi"}) - ${cardPresent.meaning || "?"}\n- Lá 3 (Tương lai): ${cardFuture.name || "?"} (${cardFuture.orientation || "Xuôi"}) - ${cardFuture.meaning || "?"}`;
  }

  const myUserPrompt = `### [CÂU HỎI MỚI]\n"${question}"\n\n${cardsSection}\n\n${historyText}\n\nGiải đáp thấu cảm và tiếp nối mạch chuyện một cách hợp lý.`;

  item.json.bodyPayload = {
    model: "n8n2",
    messages: [
      { role: "system", content: mySystemPrompt },
      { role: "user", content: myUserPrompt }
    ],
    temperature: 0.7
  };
}

return $input.all();

